                        'included' => json_encode(["Service de prise en charge et de retour à l'hôtel", 'Photos au point « Echo Sound » du désert', 'Thé bédouin servi dans une tente bédouine', 'Dîner au camp bédouin', "Safari en VTT d'une heure", 'Spectacles de danse et de feu dans le cadre de la nuit bédouine', 'Expérience de 5 minutes à dos de chameau']),
