            [
                'title' => "From Hurghada: Luxor day trip Valley of queens (by Bus)",
                'slug' => "luxor-day-trip-valley-of-queens-from-hurghada-by-bus",
                'destination_id' => 15,
                'service_type_id' => 16,
                'price_per_person' => 73.00,
                'child_price' => 36.00,
                'infant_price' => 0.00,
                'is_per_person' => 1,
                'status' => 0,
                'included' => json_encode(['Hotel pick-up and drop-off', 'Tour guide', 'Visit Valley of Queens, Hatshepsut Temple', 'Colossi of Memnon', 'Karnak Temple', 'Lunch']),
                'excluded' => json_encode(['Transfer from ( Makadi ,Sahl hasheesh, Safaga, El-Gouna, Soma Bay ) extra charge 10$ per person']),
                'short_description' => "Discover the wonders of ancient Egypt on a shared full-day trip from Hurghada to Luxor. Visit the magnificent Karnak Temple, the Temple of Queen Hatshepsut, the Colossi of Memnon, and the Valley of the Queens while traveling comfortably with fellow explorers.",
                'description' => "<h3>Overview</h3>\n<p>Embark on an unforgettable full-day shared excursion from Hurghada to Luxor, the world’s greatest open-air museum. Travel alongside fellow travelers and uncover the fascinating history of ancient Egypt as you visit some of its most celebrated archaeological treasures. Explore the vast Karnak Temple Complex, renowned for its monumental columns, sacred sanctuaries, and impressive ancient architecture. Continue to the stunning Temple of Queen Hatshepsut, beautifully carved into the dramatic cliffs of Deir el-Bahari. Stop at the iconic Colossi of Memnon, two towering statues that have stood watch over the ancient city of Thebes for millennia. Complete your journey with a visit to the Valley of the Queens, the final resting place of royal queens and princesses, adorned with remarkable tombs and rich historical significance. This shared tour offers a comfortable and sociable way to experience Luxor’s most famous landmarks in a single day, making it an ideal choice for history enthusiasts and first-time visitors alike.</p>\n<h3>Trip Highlights</h3>\n<ul>\n  <li>Visit the magnificent Karnak Temple Complex.</li>\n  <li>Explore the Temple of Queen Hatshepsut.</li>\n  <li>See the iconic Colossi of Memnon.</li>\n  <li>Discover the historic Valley of the Queens.</li>\n  <li>Enjoy a comfortable shared day trip from Hurghada.</li>\n</ul>",
                'translations' => [
                    'ar' => [
