        foreach ($trips as $tripData) {
            $translations = $tripData['translations'];
            unset($tripData['translations']);

            // Idempotency: check if slug already exists
            $existing = DB::table('services')->where('slug', $tripData['slug'])->first();
            if ($existing) {
                $this->command->info("Service with slug '{$tripData['slug']}' already exists, skipping.");
                continue;
            }

            // Create service
            $serviceId = DB::table('services')->insertGetId([
                'title' => $tripData['title'],
                'slug' => $tripData['slug'],
                'location' => 'Egypt',
                'service_type_id' => $tripData['service_type_id'],
                'destination_id' => $tripData['destination_id'],
                'price_per_person' => $tripData['price_per_person'],
                'child_price' => $tripData['child_price'],
                'infant_price' => $tripData['infant_price'],
                'deposit_required' => 0,
                'is_per_person' => 1,
                'status' => 0,
                'is_featured' => 0,
                'is_popular' => 0,
                'show_on_homepage' => 0,
                'is_new' => 1,
                'user_id' => null,
                'created_at' => now(),
                'updated_at' => now()
            ]);

            // Create default English translation record
            DB::table('service_translations')->insert([
                'service_id' => $serviceId,
                'locale' => 'en',
                'title' => $tripData['title'],
                'short_description' => $tripData['short_description'],
                'description' => $tripData['description'],
                'seo_title' => $tripData['title'],
                'seo_description' => $tripData['short_description'],
                'included' => $tripData['included'],
                'excluded' => $tripData['excluded'],
                'created_at' => now(),
                'updated_at' => now()
            ]);

            // Create translated records
            foreach ($translations as $locale => $transData) {
                DB::table('service_translations')->insert([
                    'service_id' => $serviceId,
                    'locale' => $locale,
                    'title' => $transData['title'],
                    'short_description' => $transData['short_description'],
                    'description' => $transData['description'],
                    'seo_title' => $transData['title'],
